using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator;

    public PriceCalculatorTests()
    {
        _calculator = new PriceCalculator();
    }

    // --- CalculateTotal: happy-path with DataRow ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0, 20.00, DisplayName = "Two items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 4, 0.08, 110.16, DisplayName = "Multiple items, 8% tax")]
    [DataRow(0.00, 5, 0.20, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
    [DataRow(100.00, 1, 1.0, 200.00, DisplayName = "Max tax rate (100%)")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- CalculateTotal: invalid inputs ---

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, "unitPrice", DisplayName = "Negative unit price")]
    [DataRow(10.00, -1, 0.10, "quantity", DisplayName = "Negative quantity")]
    [DataRow(10.00, 1, -0.01, "taxRate", DisplayName = "Tax rate below zero")]
    [DataRow(10.00, 1, 1.01, "taxRate", DisplayName = "Tax rate above one")]
    public void CalculateTotal_WithInvalidInput_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate, string expectedParam)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual(expectedParam, ex.ParamName);
    }

    // --- ApplyDiscount: happy-path with DynamicData + ValueTuples ---

    [TestMethod]
    [DynamicData(nameof(DiscountTestData))]
    public void ApplyDiscount_WithValidInputs_ReturnsDiscountedPrice(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> DiscountTestData =>
    [
        (100m, 0m, 100m),       // No discount
        (100m, 10m, 90m),       // 10% off
        (100m, 50m, 50m),       // Half off
        (100m, 100m, 0m),       // Full discount
        (200m, 25m, 150m),      // 25% off $200
        (0m, 50m, 0m),          // Zero price
        (59.99m, 15m, 50.9915m) // Fractional result
    ];

    // --- ApplyDiscount: invalid inputs ---

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Discount below zero")]
    [DataRow(100.01, DisplayName = "Discount above 100")]
    public void ApplyDiscount_WithInvalidDiscount_ThrowsArgumentOutOfRange(double discountPercent)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }

    // --- FormatPrice ---

    [TestMethod]
    [DataRow(19.99, "$", "$19.99", DisplayName = "Default dollar symbol")]
    [DataRow(19.99, "€", "€19.99", DisplayName = "Euro symbol")]
    [DataRow(0.00, "$", "$0.00", DisplayName = "Zero price")]
    [DataRow(1234.5, "£", "£1234.50", DisplayName = "Pads to two decimals")]
    public void FormatPrice_WithSymbol_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatPrice_WithDefaultSymbol_UsesDollarSign()
    {
        var result = _calculator.FormatPrice(42.10m);

        Assert.AreEqual("$42.10", result);
    }
}

